import{c as a,Q as t,j as s,m as i}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Thariq Claude Code Tips — Skill 設計、Session 管理與 Prompt Caching","description":"","frontmatter":{"title":"Thariq Claude Code Tips — Skill 設計、Session 管理與 Prompt Caching","source":"shanraisshan/claude-code-best-practice · Thariq","type":"best-practices"},"headers":[],"relativePath":"research/best-practices/16-thariq-tips.md","filePath":"research/best-practices/16-thariq-tips.md","lastUpdated":1779935873000}'),l={name:"research/best-practices/16-thariq-tips.md"};function o(n,e,r,d,c,h){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="thariq-claude-code-tips-—-skill-設計、session-管理與-prompt-caching" tabindex="-1">Thariq Claude Code Tips — Skill 設計、Session 管理與 Prompt Caching <a class="header-anchor" href="#thariq-claude-code-tips-—-skill-設計、session-管理與-prompt-caching" aria-label="Permalink to &quot;Thariq Claude Code Tips — Skill 設計、Session 管理與 Prompt Caching&quot;">​</a></h1><blockquote><p>來源：shanraisshan/claude-code-best-practice · Thariq (@trq212, Anthropic Claude Code 核心團隊) 收錄日期：2026-05-16（初次：2026-05-01） 涵蓋：</p><ul><li>2026-03-17: Skill 設計深度指南（9 種類型 + T1-T9 設計原則）</li><li>2026-04-16: Session 管理與 1M Context 指南</li><li>2026-04-30: Prompt Caching 核心教訓（官方 blog 文章）</li></ul></blockquote><hr><h2 id="一、skill-設計原則-t1-t9" tabindex="-1">一、Skill 設計原則（T1-T9） <a class="header-anchor" href="#一、skill-設計原則-t1-t9" aria-label="Permalink to &quot;一、Skill 設計原則（T1-T9）&quot;">​</a></h2><h3 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h3><p>Skills 的常見誤解是「只是 markdown 檔案」，但最有趣的部分是它們是<strong>資料夾</strong>，可以包含 scripts、assets、data 等 — agent 可以探索和操作的東西。Anthropic 內部有數百個 skills 在活躍使用中。</p><h3 id="t1-不要陳述顯而易見的事" tabindex="-1">T1: 不要陳述顯而易見的事 <a class="header-anchor" href="#t1-不要陳述顯而易見的事" aria-label="Permalink to &quot;T1: 不要陳述顯而易見的事&quot;">​</a></h3><p>Claude Code 對你的 codebase 知道很多，Claude 對程式設計也知道很多，包括許多預設意見。如果你的 skill 主要是關於知識，聚焦在<strong>推動 Claude 超出正常思維方式的資訊</strong>。</p><p>範例：frontend-design skill 是透過與用戶迭代改善 Claude 的設計品味而建立的 — 避免 Inter 字體和紫色漸層等經典 AI 生成設計模式。</p><h3 id="t2-建立-gotchas-區段" tabindex="-1">T2: 建立 Gotchas 區段 <a class="header-anchor" href="#t2-建立-gotchas-區段" aria-label="Permalink to &quot;T2: 建立 Gotchas 區段&quot;">​</a></h3><p>Skill 中信號密度最高的內容是 Gotchas 區段。這些區段應該從 Claude 使用你的 skill 時遇到的常見失敗點中累積。隨時間更新 skill 來捕捉這些 gotchas。</p><h3 id="t3-使用檔案系統與-progressive-disclosure" tabindex="-1">T3: 使用檔案系統與 Progressive Disclosure <a class="header-anchor" href="#t3-使用檔案系統與-progressive-disclosure" aria-label="Permalink to &quot;T3: 使用檔案系統與 Progressive Disclosure&quot;">​</a></h3><p>Skill 是資料夾，不只是 markdown 檔案。把整個檔案系統視為 context engineering 和 progressive disclosure 的形式：</p><ul><li>告訴 Claude 你的 skill 中有哪些檔案，它會在適當時機讀取它們</li><li>最簡單的形式：指向其他 markdown 檔案（例如把詳細函式簽名和使用範例拆到 <code>references/api.md</code>）</li><li>可以有 references、scripts、examples 等資料夾</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>skills/my-skill/</span></span>
<span class="line"><span>  SKILL.md            ← 核心指引和 TOC</span></span>
<span class="line"><span>  references/api.md   ← 詳細 API 文件</span></span>
<span class="line"><span>  scripts/helper.sh   ← 可執行腳本</span></span>
<span class="line"><span>  examples/           ← 使用範例</span></span></code></pre></div><h3 id="t4-避免-railroading-claude" tabindex="-1">T4: 避免 Railroading Claude <a class="header-anchor" href="#t4-避免-railroading-claude" aria-label="Permalink to &quot;T4: 避免 Railroading Claude&quot;">​</a></h3><p>Claude 通常會嘗試遵循你的指示，因為 skills 非常可重用，要小心過於具體：</p><ul><li>給 Claude 它需要的資訊，但給它<strong>適應情況的靈活性</strong></li><li>不要開出逐步的詳細指示，<strong>給目標和限制</strong></li><li>過度具體的 skill 在邊界情況會失敗</li></ul><h3 id="t5-思考-setup" tabindex="-1">T5: 思考 Setup <a class="header-anchor" href="#t5-思考-setup" aria-label="Permalink to &quot;T5: 思考 Setup&quot;">​</a></h3><p>有些 skill 需要用戶的 context 才能運作。好的模式是在 skill 目錄中儲存 <code>config.json</code>：</p><ul><li>如果 config 未設定，agent 可以詢問用戶資訊</li><li>可以指示 Claude 使用 AskUserQuestion tool 進行結構化、多選問題</li></ul><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// skills/my-skill/config.json</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;target_service&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;environment&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;staging&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="t6-description-欄位是寫給模型的" tabindex="-1">T6: Description 欄位是寫給模型的 <a class="header-anchor" href="#t6-description-欄位是寫給模型的" aria-label="Permalink to &quot;T6: Description 欄位是寫給模型的&quot;">​</a></h3><p>Claude Code 啟動 session 時，會建立所有可用 skill 及其 description 的列表。這個列表是 Claude 掃描「有沒有適合這個請求的 skill？」的依據。</p><p><strong>description 欄位不是摘要 — 它是觸發條件的描述。為模型寫它。</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  Use when deploying to production. Triggers on: &quot;deploy&quot;, &quot;push to prod&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;release to live&quot;. Do NOT use for: staging deploys, local testing.</span></span></code></pre></div><h3 id="t7-memory-與資料儲存" tabindex="-1">T7: Memory 與資料儲存 <a class="header-anchor" href="#t7-memory-與資料儲存" aria-label="Permalink to &quot;T7: Memory 與資料儲存&quot;">​</a></h3><p>有些 skill 可以透過儲存資料來包含記憶：</p><ul><li>簡單：append-only text log 或 JSON 檔案</li><li>複雜：SQLite 資料庫</li></ul><p><strong>重要</strong>：skill 目錄中的資料在升級 skill 時可能被刪除。使用 <code>\${CLAUDE_PLUGIN_DATA}</code> 作為穩定的每個 plugin 資料儲存資料夾。</p><h3 id="t8-儲存-scripts-與生成程式碼" tabindex="-1">T8: 儲存 Scripts 與生成程式碼 <a class="header-anchor" href="#t8-儲存-scripts-與生成程式碼" aria-label="Permalink to &quot;T8: 儲存 Scripts 與生成程式碼&quot;">​</a></h3><p>給 Claude 最強大的工具之一是<strong>程式碼本身</strong>。提供 scripts 和 libraries 讓 Claude 把 turns 花在組合和決策上，而不是重建 boilerplate：</p><ul><li>Claude 可以即時生成 scripts 來組合這些功能進行更進階的分析</li><li>Scripts 提供確定性的操作，降低 Claude 犯錯的機率</li></ul><h3 id="t9-按需-hooks-on-demand-hooks" tabindex="-1">T9: 按需 Hooks（On Demand Hooks） <a class="header-anchor" href="#t9-按需-hooks-on-demand-hooks" aria-label="Permalink to &quot;T9: 按需 Hooks（On Demand Hooks）&quot;">​</a></h3><p>Skills 可以包含只在 skill 被呼叫時啟動、持續到 session 結束的 hooks。適合不想一直執行但有時極有用的 opinionated hooks：</p><ul><li><code>/careful</code> — 透過 PreToolUse matcher 阻擋 <code>rm -rf</code>、<code>DROP TABLE</code>、force-push、<code>kubectl delete</code></li><li><code>/freeze</code> — 阻擋任何不在特定目錄的 Edit/Write</li></ul><hr><h2 id="二、9-種-skill-類型" tabindex="-1">二、9 種 Skill 類型 <a class="header-anchor" href="#二、9-種-skill-類型" aria-label="Permalink to &quot;二、9 種 Skill 類型&quot;">​</a></h2><p>Anthropic 團隊整理所有 skills 後，發現它們聚集成 9 個類別。最好的 skills 清楚屬於其中一類；令人困惑的往往橫跨多類。</p><h3 id="類型-1-library-api-reference-函式庫-api-參考" tabindex="-1">類型 1: Library &amp; API Reference（函式庫 API 參考） <a class="header-anchor" href="#類型-1-library-api-reference-函式庫-api-參考" aria-label="Permalink to &quot;類型 1: Library &amp; API Reference（函式庫 API 參考）&quot;">​</a></h3><p>解釋如何正確使用函式庫、CLI 或 SDK 的 skills：</p><ul><li>適合內部函式庫或 Claude 有時有困難的常用函式庫</li><li>通常包含參考程式碼片段資料夾和要避免的 gotchas 列表</li></ul><p><strong>範例</strong>：<code>billing-lib</code>、<code>internal-platform-cli</code>、<code>frontend-design</code></p><h3 id="類型-2-product-verification-產品驗證" tabindex="-1">類型 2: Product Verification（產品驗證） <a class="header-anchor" href="#類型-2-product-verification-產品驗證" aria-label="Permalink to &quot;類型 2: Product Verification（產品驗證）&quot;">​</a></h3><p>描述如何測試或驗證程式碼正確性的 skills：</p><ul><li>通常配合 Playwright、tmux 等外部工具</li><li>驗證 skills 對確保 Claude 輸出正確極有價值</li><li><strong>值得讓工程師花一週時間把驗證 skills 做到優秀</strong></li></ul><p><strong>範例</strong>：<code>signup-flow-driver</code>、<code>checkout-verifier</code>、<code>tmux-cli-driver</code></p><h3 id="類型-3-data-fetching-analysis-資料抓取與分析" tabindex="-1">類型 3: Data Fetching &amp; Analysis（資料抓取與分析） <a class="header-anchor" href="#類型-3-data-fetching-analysis-資料抓取與分析" aria-label="Permalink to &quot;類型 3: Data Fetching &amp; Analysis（資料抓取與分析）&quot;">​</a></h3><p>連接到你的資料和監控 stack 的 skills：</p><ul><li>可能包含帶 credentials 的資料抓取 libraries、特定 dashboard ID</li><li>以及常見工作流程或資料取得方式的說明</li></ul><p><strong>範例</strong>：<code>funnel-query</code>、<code>cohort-compare</code>、<code>grafana</code></p><h3 id="類型-4-business-process-team-automation-業務流程與團隊自動化" tabindex="-1">類型 4: Business Process &amp; Team Automation（業務流程與團隊自動化） <a class="header-anchor" href="#類型-4-business-process-team-automation-業務流程與團隊自動化" aria-label="Permalink to &quot;類型 4: Business Process &amp; Team Automation（業務流程與團隊自動化）&quot;">​</a></h3><p>將重複工作流程自動化為單一命令的 skills：</p><ul><li>通常是相對簡單的指示，但可能對其他 skills 或 MCP 有更複雜的依賴</li><li>在 log 檔案中儲存先前結果可幫助模型保持一致性並反思先前執行</li></ul><p><strong>範例</strong>：<code>standup-post</code>、<code>create-&lt;ticket-system&gt;-ticket</code>、<code>weekly-recap</code></p><h3 id="類型-5-code-scaffolding-templates-程式碼-scaffolding-與模板" tabindex="-1">類型 5: Code Scaffolding &amp; Templates（程式碼 Scaffolding 與模板） <a class="header-anchor" href="#類型-5-code-scaffolding-templates-程式碼-scaffolding-與模板" aria-label="Permalink to &quot;類型 5: Code Scaffolding &amp; Templates（程式碼 Scaffolding 與模板）&quot;">​</a></h3><p>為 codebase 中特定功能生成框架 boilerplate 的 skills：</p><ul><li>可以與可組合的 scripts 結合</li><li>在 scaffolding 有自然語言需求（純程式碼無法完全涵蓋）時特別有用</li></ul><p><strong>範例</strong>：<code>new-&lt;framework&gt;-workflow</code>、<code>new-migration</code>、<code>create-app</code></p><h3 id="類型-6-code-quality-review-程式碼品質與審查" tabindex="-1">類型 6: Code Quality &amp; Review（程式碼品質與審查） <a class="header-anchor" href="#類型-6-code-quality-review-程式碼品質與審查" aria-label="Permalink to &quot;類型 6: Code Quality &amp; Review（程式碼品質與審查）&quot;">​</a></h3><p>在你的組織中強制執行程式碼品質並幫助 review 程式碼的 skills：</p><ul><li>可以包含確定性 scripts 或工具以獲得最大穩健性</li><li>可以作為 hooks 的一部分或在 GitHub Action 中自動執行</li></ul><p><strong>範例</strong>：<code>adversarial-review</code>、<code>code-style</code>、<code>testing-practices</code></p><h3 id="類型-7-ci-cd-deployment-ci-cd-與部署" tabindex="-1">類型 7: CI/CD &amp; Deployment（CI/CD 與部署） <a class="header-anchor" href="#類型-7-ci-cd-deployment-ci-cd-與部署" aria-label="Permalink to &quot;類型 7: CI/CD &amp; Deployment（CI/CD 與部署）&quot;">​</a></h3><p>幫助你在 codebase 中 fetch、push 和部署程式碼的 skills：</p><ul><li>這些 skills 可能引用其他 skills 來收集資料</li></ul><p><strong>範例</strong>：<code>babysit-pr</code>、<code>deploy-&lt;service&gt;</code>、<code>cherry-pick-prod</code></p><h3 id="類型-8-runbooks-運行手冊" tabindex="-1">類型 8: Runbooks（運行手冊） <a class="header-anchor" href="#類型-8-runbooks-運行手冊" aria-label="Permalink to &quot;類型 8: Runbooks（運行手冊）&quot;">​</a></h3><p>接受症狀（如 Slack thread、alert 或錯誤特徵），走過多工具調查，並產出結構化報告的 skills：</p><p><strong>範例</strong>：<code>&lt;service&gt;-debugging</code>、<code>oncall-runner</code>、<code>log-correlator</code></p><h3 id="類型-9-infrastructure-operations-基礎設施操作" tabindex="-1">類型 9: Infrastructure Operations（基礎設施操作） <a class="header-anchor" href="#類型-9-infrastructure-operations-基礎設施操作" aria-label="Permalink to &quot;類型 9: Infrastructure Operations（基礎設施操作）&quot;">​</a></h3><p>執行例行維護和操作程序的 skills — 部分涉及受益於 guardrails 的破壞性操作：</p><p><strong>範例</strong>：<code>&lt;resource&gt;-orphans</code>、<code>dependency-management</code>、<code>cost-investigation</code></p><hr><h2 id="三、skill-分發與治理" tabindex="-1">三、Skill 分發與治理 <a class="header-anchor" href="#三、skill-分發與治理" aria-label="Permalink to &quot;三、Skill 分發與治理&quot;">​</a></h2><h3 id="兩種分發方式" tabindex="-1">兩種分發方式 <a class="header-anchor" href="#兩種分發方式" aria-label="Permalink to &quot;兩種分發方式&quot;">​</a></h3><ol><li><strong>Check in 到 repo</strong>（放在 <code>.claude/skills/</code> 下）— 適合在少數 repo 工作的小型團隊</li><li><strong>建立 plugin</strong> 並有 Claude Code Plugin marketplace — 規模化時的選擇</li></ol><p>每個 check in 的 skill 都會讓模型的 context 增加一點。規模化時，內部 plugin marketplace 讓你分發 skills 並讓團隊決定安裝哪些。</p><h3 id="marketplace-管理" tabindex="-1">Marketplace 管理 <a class="header-anchor" href="#marketplace-管理" aria-label="Permalink to &quot;Marketplace 管理&quot;">​</a></h3><p>沒有集中的團隊決定哪些 skills 進入 marketplace。做法：</p><ol><li>上傳到 GitHub 的 sandbox 資料夾</li><li>在 Slack 或論壇推廣</li><li>一旦 skill 獲得足夠關注（由 skill 擁有者決定），提 PR 移入 marketplace</li><li>在發布前進行策展，避免冗餘 skills</li></ol><h3 id="skill-組合" tabindex="-1">Skill 組合 <a class="header-anchor" href="#skill-組合" aria-label="Permalink to &quot;Skill 組合&quot;">​</a></h3><p>Skills 可以互相依賴。直接在 skill 中按名稱引用其他 skills，模型會在安裝時呼叫它們：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">此 skill 依賴 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`file-upload\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> skill 來上傳結果。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">請確保已安裝 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`file-upload\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> skill。</span></span></code></pre></div><h3 id="量測-skills" tabindex="-1">量測 Skills <a class="header-anchor" href="#量測-skills" aria-label="Permalink to &quot;量測 Skills&quot;">​</a></h3><p>使用 <code>PreToolUse</code> hook 記錄 skill 使用狀況：</p><ul><li>找出受歡迎的 skills</li><li>發現觸發率低於預期的 skills</li></ul><hr><h2 id="四、session-管理-1m-context-時代" tabindex="-1">四、Session 管理（1M Context 時代） <a class="header-anchor" href="#四、session-管理-1m-context-時代" aria-label="Permalink to &quot;四、Session 管理（1M Context 時代）&quot;">​</a></h2><h3 id="context-rot-原理" tabindex="-1">Context Rot 原理 <a class="header-anchor" href="#context-rot-原理" aria-label="Permalink to &quot;Context Rot 原理&quot;">​</a></h3><p>「Context window 是模型在生成下一個回應時能『看到』的一切。」包含：system prompts、對話歷史、tool calls、檔案讀取。</p><p><strong>Context rot</strong>：隨著 context 增長，模型效能下降，因為注意力分散在更多 tokens 上。1M context 模型通常在約 300-400k tokens 開始出現，但依任務類型而異。</p><h3 id="每個-turn-都是分支點" tabindex="-1">每個 Turn 都是分支點 <a class="header-anchor" href="#每個-turn-都是分支點" aria-label="Permalink to &quot;每個 Turn 都是分支點&quot;">​</a></h3><p>Claude 完成一個 turn 後，有幾個選擇：</p><table tabindex="0"><thead><tr><th>情況</th><th>使用</th><th>原因</th></tr></thead><tbody><tr><td>同一任務、context 仍相關</td><td><strong>Continue</strong></td><td>所有內容仍 load-bearing，不要白花錢重建</td></tr><tr><td>走錯路徑</td><td><strong>Rewind</strong>（Esc Esc）</td><td>保留讀取，丟掉失敗，用所學重新 prompt</td></tr><tr><td>中途 session 膨脹</td><td><strong>/compact &lt;hint&gt;</strong></td><td>低 effort；Claude 決定相關性</td></tr><tr><td>開始新任務</td><td><strong>/clear</strong></td><td>零 rot；完全控制帶入的 context</td></tr><tr><td>下一步會產生大量中間輸出</td><td><strong>Subagent</strong></td><td>中間雜訊留在 child context</td></tr></tbody></table><h3 id="何時開新-session" tabindex="-1">何時開新 Session <a class="header-anchor" href="#何時開新-session" aria-label="Permalink to &quot;何時開新 Session&quot;">​</a></h3><p>「當你開始新任務，你也應該開新 session。」</p><p>灰色地帶：相關任務需要部分但非全部 context，例如為剛實作的功能寫文件。</p><h3 id="rewind-優於口頭修正" tabindex="-1">Rewind 優於口頭修正 <a class="header-anchor" href="#rewind-優於口頭修正" aria-label="Permalink to &quot;Rewind 優於口頭修正&quot;">​</a></h3><p>不要在失敗嘗試後口頭說「那個沒用，試 X」（失敗嘗試仍留在 context 污染後續）。</p><p>Rewind 移除失敗並用學到的資訊重新 prompt。「Summarize from here」功能建立 handoff messages，記錄嘗試過什麼和為什麼失敗。</p><h3 id="compact-vs-清空重開" tabindex="-1">Compact vs 清空重開 <a class="header-anchor" href="#compact-vs-清空重開" aria-label="Permalink to &quot;Compact vs 清空重開&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th><code>/compact</code></th><th><code>/clear</code> + 手寫摘要</th></tr></thead><tbody><tr><td>誰寫摘要</td><td>Claude 自動</td><td>你自己</td></tr><tr><td>損失</td><td>lossy（可能漏關鍵）</td><td>零 rot</td></tr><tr><td>成本</td><td>低（自動）</td><td>高（人工寫摘要）</td></tr><tr><td>控制度</td><td>可用 hint 引導</td><td>完全自控</td></tr></tbody></table><p><strong>Bad compact 的成因</strong>：autocompact 在 context rot 最嚴重時觸發 — 模型此時最不聰明，可能丟掉關鍵細節。</p><h3 id="subagents-—-context-管理的形式" tabindex="-1">Subagents — Context 管理的形式 <a class="header-anchor" href="#subagents-—-context-管理的形式" aria-label="Permalink to &quot;Subagents — Context 管理的形式&quot;">​</a></h3><p>「Subagents 是 context 管理的一種形式，在你提前知道一塊工作會產生大量不需要再用的中間輸出時很有用。」</p><p>Subagents 有自己的新鮮 context windows，只把最終報告回傳給 parent context。</p><p><strong>Mental test</strong>：「我需要這個工具輸出本身，還是只需要結論？」</p><ul><li>只需要結論 → 委派 subagent</li><li>需要反覆檢視中間產物 → 主對話自己做</li></ul><hr><h2 id="五、工程哲學" tabindex="-1">五、工程哲學 <a class="header-anchor" href="#五、工程哲學" aria-label="Permalink to &quot;五、工程哲學&quot;">​</a></h2><h3 id="unhobbling-—-移除不必要的限制" tabindex="-1">Unhobbling — 移除不必要的限制 <a class="header-anchor" href="#unhobbling-—-移除不必要的限制" aria-label="Permalink to &quot;Unhobbling — 移除不必要的限制&quot;">​</a></h3><p>傳統軟體工具是為人類設計的，為人類建立了很多 guardrails 和限制。當 AI agent 使用這些工具時，這些限制可能反而成為障礙。</p><p>設計供 agent 使用的 skills/tools 時，問：「這個限制是為了保護人類免於錯誤，還是為了保護系統？」保護系統的限制通常 agent 不需要；保護人類決策完整性的限制可能需要保留或以新方式實現。</p><h3 id="delete-and-rebuild-重建優於修補" tabindex="-1">Delete-and-Rebuild（重建優於修補） <a class="header-anchor" href="#delete-and-rebuild-重建優於修補" aria-label="Permalink to &quot;Delete-and-Rebuild（重建優於修補）&quot;">​</a></h3><p>當你的 Claude 設定開始感覺像是在修補修補的修補時，考慮從頭重建：</p><ul><li>Skills 從一個 SKILL.md 和單一 gotcha 開始</li><li>隨著 Claude 碰到新邊界情況而逐漸改善</li><li>不要害怕刪掉已過時的 skills 並重建更清晰的版本</li></ul><p>「我們大多數的 skills 從幾行和一個 gotcha 開始，因為人們不斷加入 Claude 碰到的新邊界情況而變得更好。」</p><h3 id="seeing-like-an-agent-以-agent-的視角看問題" tabindex="-1">Seeing like an Agent（以 Agent 的視角看問題） <a class="header-anchor" href="#seeing-like-an-agent-以-agent-的視角看問題" aria-label="Permalink to &quot;Seeing like an Agent（以 Agent 的視角看問題）&quot;">​</a></h3><p>設計 skills 時，想象 Claude 在看到這個 skill 時的視角：</p><ul><li>它會在什麼情況下觸發這個 skill？（description 欄位的重要性）</li><li>它需要什麼資訊才能成功？（避免過度詳細或過度簡略）</li><li>什麼情況會讓它失敗？（Gotchas 區段的來源）</li></ul><p>Anthropic 的 frontend-design skill 就是這個哲學的體現：不是列出所有設計規則，而是聚焦在 Claude 最常犯的、最需要被糾正的特定錯誤上。</p><hr><hr><h2 id="三、prompt-caching-心法-2026-04-30-官方-blog" tabindex="-1">三、Prompt Caching 心法（2026-04-30 官方 Blog） <a class="header-anchor" href="#三、prompt-caching-心法-2026-04-30-官方-blog" aria-label="Permalink to &quot;三、Prompt Caching 心法（2026-04-30 官方 Blog）&quot;">​</a></h2><blockquote><p>來源：<a href="https://claude.com/blog/lessons-from-building-claude-code-prompt-caching-is-everything" target="_blank" rel="noreferrer">https://claude.com/blog/lessons-from-building-claude-code-prompt-caching-is-everything</a><br> 完整分析見：<code>research/best-practices/28-thariq-prompt-caching-lessons.md</code></p></blockquote><h3 id="核心立場" tabindex="-1">核心立場 <a class="header-anchor" href="#核心立場" aria-label="Permalink to &quot;核心立場&quot;">​</a></h3><p>Claude Code 團隊將 <strong>Cache Hit Rate 視為關鍵指標，下降時觸發 incident</strong>。不是優化項，是生產系統基本健康指標。</p><h3 id="分層結構-靜態-→-動態" tabindex="-1">分層結構（靜態 → 動態） <a class="header-anchor" href="#分層結構-靜態-→-動態" aria-label="Permalink to &quot;分層結構（靜態 → 動態）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. System prompt + Tools       ← 最穩定，全域快取</span></span>
<span class="line"><span>2. 專案特定檔案 / CLAUDE.md   ← 跨 session 快取</span></span>
<span class="line"><span>3. Session context             ← 僅當次 session</span></span>
<span class="line"><span>4. 對話訊息（最新輪次）        ← 每次請求不同</span></span></code></pre></div><p>越靠前越穩定，快取效益越高。</p><h3 id="五個禁止事項" tabindex="-1">五個禁止事項 <a class="header-anchor" href="#五個禁止事項" aria-label="Permalink to &quot;五個禁止事項&quot;">​</a></h3><table tabindex="0"><thead><tr><th>禁止</th><th>原因</th><th>正確做法</th></tr></thead><tbody><tr><td>動態更新 system prompt</td><td>前綴失效</td><td>用 <code>&lt;system-reminder&gt;</code> 注入動態資訊</td></tr><tr><td>Mid-session 切換模型</td><td>快取模型專屬</td><td>用 Subagent 處理需不同模型的任務</td></tr><tr><td>對話中增刪工具</td><td>前綴失效</td><td>stub + <code>defer_loading: true</code></td></tr><tr><td>Compact 時改 system prompt</td><td>後續快取失效</td><td>Compact 保留完全相同的 system prompt + tools</td></tr><tr><td>忽略 cache hit rate</td><td>沉默降解</td><td>加入 observability dashboard</td></tr></tbody></table><h3 id="關鍵引言" tabindex="-1">關鍵引言 <a class="header-anchor" href="#關鍵引言" aria-label="Permalink to &quot;關鍵引言&quot;">​</a></h3><blockquote><p>「Cache rules everything. We treat it like uptime. When it drops, we have an incident.」 — Thariq Shihipar, Claude Code MTS</p></blockquote><hr><h2 id="附錄-thariq-在-workspace-rules-中的引用" tabindex="-1">附錄：Thariq 在 Workspace Rules 中的引用 <a class="header-anchor" href="#附錄-thariq-在-workspace-rules-中的引用" aria-label="Permalink to &quot;附錄：Thariq 在 Workspace Rules 中的引用&quot;">​</a></h2><p>以下是已整合到本 workspace 規則中的 Thariq 觀點，供對照：</p><ul><li><strong>Context rot 閾值</strong>（300-400k tokens）→ <code>.claude/rules/context-management.md</code></li><li><strong>Subagent mental test</strong>（conclusion vs. tool output）→ <code>.claude/rules/subagent-strategy.md</code></li><li><strong>Prompt caching 架構規則</strong>（static first, dynamic last）→ <code>.claude/rules/context-management.md</code></li><li><strong>1M context + compact 策略</strong>（壓縮層級決策表）→ <code>.claude/rules/context-management.md</code></li><li><strong>Session branching point</strong>（每個 turn 的六個選擇）→ <code>.claude/rules/session-management.md</code></li><li><strong>Forked Subagent / context 繼承</strong>（v2.1.117）→ <code>.claude/rules/subagent-advanced.md</code></li><li><strong>Prompt caching 五禁止事項</strong>（2026-04-30）→ <code>28-thariq-prompt-caching-lessons.md</code></li></ul>`,139)])])}const k=a(l,[["render",o]]);export{u as __pageData,k as default};
